import json, re, hmac, hashlib, time
from jsonschema import validate, ValidationError

WEBHOOK_SCHEMA = {
    "type": "object",
    "required": ["task_id", "status", "completed_at"],
    "properties": {
        "task_id": {"type": "string",
                    "pattern": r"^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$"},
        "status": {"type": "string", "enum": ["completed", "failed"]},
        "result": {"type": ["string", "null"]},
        "error": {"type": ["string", "null"]},
        "completed_at": {"type": "string"},
    },
    "additionalProperties": False,
}


def validate_webhook_payload(payload: dict) -> None:
    validate(instance=payload, schema=WEBHOOK_SCHEMA)


def verify_webhook_signature(body: bytes, signature_header: str, secret: str) -> bool:
    expected = hmac.new(secret.encode(), body, hashlib.sha256).hexdigest()
    received = signature_header.removeprefix("sha256=")
    return hmac.compare_digest(expected, received)


def validate_jwt_claims(payload: dict, required_scope: str) -> None:
    if "exp" not in payload:
        raise ValueError("JWT missing exp claim")
    if payload["exp"] < time.time():
        raise ValueError("JWT has expired")
    scopes = payload.get("scope", "").split()
    if required_scope not in scopes:
        raise ValueError(f"Required scope '{required_scope}' not granted")


def detect_breaking_changes(old_schema: dict, new_schema: dict, path: str = "") -> list[str]:
    issues = []
    old_props = old_schema.get("properties", {})
    new_props = new_schema.get("properties", {})
    old_required = set(old_schema.get("required", []))
    new_required = set(new_schema.get("required", []))

    for field in old_props:
        if field not in new_props:
            issues.append(f"BREAKING: field '{path}.{field}' removed")
        elif old_props[field].get("type") != new_props[field].get("type"):
            issues.append(f"BREAKING: '{path}.{field}' type changed")

    for field in (new_required - old_required):
        issues.append(f"BREAKING: '{path}.{field}' newly required")

    return issues


if __name__ == "__main__":
    v1 = {
        "type": "object",
        "required": ["prompt", "webhook_url"],
        "properties": {
            "prompt": {"type": "string"},
            "webhook_url": {"type": "string"},
            "metadata": {"type": "object"},
        },
    }
    v2_bad = {
        "type": "object",
        "required": ["prompt", "webhook_url", "caller_id"],
        "properties": {
            "prompt": {"type": "string"},
            "webhook_url": {"type": "string"},
            "caller_id": {"type": "string"},
        },
    }
    for issue in detect_breaking_changes(v1, v2_bad, path="TaskRequest"):
        print(issue)
    # BREAKING: field 'TaskRequest.metadata' removed
    # BREAKING: 'TaskRequest.caller_id' newly required
